export const subjects = [
  {
    id: "matematika",
    name: "Matematika",
    questions: questionsList,
  }
];

export const getQuestionsByVariant = (subjectId: string, variant: number): Question[] => {
  const subject = subjects.find(s => s.id === subjectId);
  if (!subject) return [];
  const variantSize = 30;
  const start = (variant - 1) * variantSize;
  const end = start + variantSize;
  return subject.questions.slice(start, end);
};

export const totalVariantsForSubject = (subjectId: string): number => {
  const subject = subjects.find(s => s.id === subjectId);
  if (!subject) return 0;
  return Math.ceil(subject.questions.length / 30) || 1;
};

export const totalVariants = Math.ceil(questionsList.length / 30) || 1;

